package genxsolution.vms.vmsbackend.maintenance_management.maintenance_strategy.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_strategy.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_strategy.mapper.MaintenanceStrategyMapper; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_strategy.repository.MaintenanceStrategyRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class MaintenanceStrategyService { private final MaintenanceStrategyRepository repository; private final MaintenanceStrategyMapper mapper; public MaintenanceStrategyService(MaintenanceStrategyRepository repository,MaintenanceStrategyMapper mapper){this.repository=repository;this.mapper=mapper;} public List<MaintenanceStrategyResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public MaintenanceStrategyResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceStrategy", String.valueOf(id))); } public MaintenanceStrategyResponse create(MaintenanceStrategyUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public MaintenanceStrategyResponse update(UUID id,MaintenanceStrategyUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceStrategy", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("MaintenanceStrategy", String.valueOf(id)); } }
